sequence.script:
var payload = mc.getPayloadJSON();

function pad(num, size) {

    var s = num + "";

    while (s.length < size) {
        s = "0" + s;
    }

    return s;
}

function getTimestamp() {

    var now = new Date();

    return now.getFullYear() +
        pad(now.getMonth() + 1, 2) +
        pad(now.getDate(), 2) +
        pad(now.getHours(), 2) +
        pad(now.getMinutes(), 2) +
        pad(now.getSeconds(), 2) +
        pad(now.getMilliseconds(), 3);
}

var ts = getTimestamp();

var result = [];

// Payload is ARRAY
if (payload && payload.length > 0) {

    for (var i = 0; i < payload.length; i++) {

        var vehicle = payload[i];

        // Skip accidental duplicated header row
        if (
            vehicle.vehicleIdentificationNumber === "vehicleIdentificationNumber"
        ) {
            continue;
        }

        vehicle.insurableObjectIdentifier =
            "VEH-" + ts + "-" + (result.length + 1);

        vehicle.status = "ACTIVE";

        result.push(vehicle);
    }
}

// Set final payload
mc.setPayloadJSON({
    vehicles: result
});
